def run_workflow(task_query):
    st.session_state.running = True
    st.session_state.logs = []
    st.session_state.current_page = "Mission Control"
    
    workflow = get_workflow()
    initial_state = {
        "task": task_query,
        "plan": [],
        "current_step": 0,
        "research_data": [],
        "analysis_results": "",
        "metrics": {},
        "citations": [],
        "draft_report": "",
        "critique_score": 0,
        "feedback": "",
        "iteration": 0,
        "max_iterations": 1
    }
    
    st.session_state.agent_state = initial_state
    
    # Progress monitoring
    placeholder = st.empty()
    
    for event in workflow.stream(initial_state):
        for node, next_state in event.items():
            if node == "StepIncrement": continue
            st.session_state.agent_state.update(next_state)
            st.session_state.logs.append(f"🛰️ **{node}** pulse detected. Synchronization in progress.")
            time.sleep(0.1)
            
    st.session_state.running = False
    st.rerun()

